func NewRuntimeTerminateExecution() tools.Tool {
	return tools.Tool{
		Name:        "cdp.runtime.terminateExecution",
		Description: "Terminate current or next JavaScript execution.\nWill cancel the termination when the outer-most script execution ends. (CDP: Runtime.terminateExecution)",
		Schema:      json.RawMessage(runtimeTerminateExecutionSchema),
		Run:         runRuntimeTerminateExecution,
	}
}

func runRuntimeTerminateExecution(ctx context.Context, raw json.RawMessage, env *tools.RunEnv) tools.Result {
	if !env.AllowDangerous {
		return tools.Fail(tools.CategoryUnsupported, "dangerous_disabled",
			"Runtime.terminateExecution is gated behind --allow-dangerous-cdp / OAMCP_ALLOW_DANGEROUS_CDP=1", false)
	}
	var p runtimeTerminateExecutionParams
	if len(raw) > 0 {
		if err := json.Unmarshal(raw, &p); err != nil {
			return tools.Fail(tools.CategoryValidation, "param_decode", err.Error(), false)
		}
	}
	att, err := env.Attach(ctx, tools.TargetSelector{TargetID: p.TargetID, URLPattern: p.URLPattern})
	if err != nil {
		return tools.Fail(tools.CategoryNotFound, "attach_failed", err.Error(), false)
	}
	if err := env.EnsureEnabled(ctx, att.SessionID, "Runtime"); err != nil {
		return tools.ClassifyCDPErr("enable_failed", err)
	}
	out, err := att.Conn.Send(ctx, att.SessionID, "Runtime.terminateExecution", nil)
	if err != nil {
		return tools.ClassifyCDPErr("runtime_terminate_execution_failed", err)
	}
	return tools.OK(json.RawMessage(out))
}

// RegisterRuntime adds every generated Runtime tool to the registry.
func RegisterRuntime(r *tools.Registry) {
	r.MustRegister(NewRuntimeAddBinding())
	r.MustRegister(NewRuntimeAwaitPromise())
	r.MustRegister(NewRuntimeCallFunctionOn())
	r.MustRegister(NewRuntimeCompileScript())
	r.MustRegister(NewRuntimeDiscardConsoleEntries())
	r.MustRegister(NewRuntimeEvaluate())
	r.MustRegister(NewRuntimeGetExceptionDetails())
	r.MustRegister(NewRuntimeGetHeapUsage())
	r.MustRegister(NewRuntimeGetIsolateId())
	r.MustRegister(NewRuntimeGetProperties())
	r.MustRegister(NewRuntimeGlobalLexicalScopeNames())
	r.MustRegister(NewRuntimeQueryObjects())
	r.MustRegister(NewRuntimeReleaseObject())
	r.MustRegister(NewRuntimeReleaseObjectGroup())
	r.MustRegister(NewRuntimeRemoveBinding())
	r.MustRegister(NewRuntimeRunIfWaitingForDebugger())
	r.MustRegister(NewRuntimeRunScript())
	r.MustRegister(NewRuntimeSetAsyncCallStackDepth())
	r.MustRegister(NewRuntimeSetCustomObjectFormatterEnabled())
	r.MustRegister(NewRuntimeSetMaxCallStackSizeToCapture())
	r.MustRegister(NewRuntimeTerminateExecution())
}
